document.addEventListener('DOMContentLoaded', function() {
    // 1. Smooth scroll for anchor links
    document.addEventListener('click', function(e) {
        const anchor = e.target.closest('a[href^="#"]');
        if (!anchor) return;
        
        const targetId = anchor.getAttribute('href');
        if (targetId === '#') return;
        
        const targetElement = document.querySelector(targetId);
        if (!targetElement) return;
        
        e.preventDefault();
        
        targetElement.scrollIntoView({
            behavior: 'smooth',
            block: 'start'
        });
    });

    // 2. Navbar scroll effect
    const navbar = document.querySelector('.navbar');
    if (navbar) {
        let scrollTimeout;
        
        function updateNavbarClass() {
            if (window.scrollY > 50) {
                navbar.classList.add('navbar-scrolled');
            } else {
                navbar.classList.remove('navbar-scrolled');
            }
        }
        
        window.addEventListener('scroll', function() {
            if (scrollTimeout) {
                cancelAnimationFrame(scrollTimeout);
            }
            scrollTimeout = requestAnimationFrame(updateNavbarClass);
        }, { passive: true });
        
        updateNavbarClass();
    }

    // 3. Form validation for contact form
    const contactForm = document.querySelector('.contact-form');
    if (contactForm) {
        const errorMessages = {};
        
        function showError(input, message) {
            let errorEl = input.parentElement.querySelector('.form-error');
            if (!errorEl) {
                errorEl = document.createElement('span');
                errorEl.className = 'form-error';
                errorEl.style.color = '#dc3545';
                errorEl.style.fontSize = '0.875rem';
                errorEl.style.marginTop = '0.25rem';
                errorEl.style.display = 'block';
                input.parentElement.appendChild(errorEl);
            }
            errorEl.textContent = message;
            input.classList.add('input-error');
            input.style.borderColor = '#dc3545';
        }
        
        function clearError(input) {
            const errorEl = input.parentElement.querySelector('.form-error');
            if (errorEl) {
                errorEl.remove();
            }
            input.classList.remove('input-error');
            input.style.borderColor = '';
        }
        
        function validateEmail(email) {
            const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            return re.test(email);
        }
        
        function validateField(input) {
            const value = input.value.trim();
            
            if (input.hasAttribute('required') && !value) {
                const fieldName = input.getAttribute('name') || input.getAttribute('placeholder') || 'This field';
                showError(input, fieldName + ' is required');
                return false;
            }
            
            if (input.type === 'email' && value && !validateEmail(value)) {
                showError(input, 'Please enter a valid email address');
                return false;
            }
            
            if (input.hasAttribute('minlength') && value.length < parseInt(input.getAttribute('minlength'))) {
                showError(input, 'Minimum ' + input.getAttribute('minlength') + ' characters required');
                return false;
            }
            
            clearError(input);
            return true;
        }
        
        contactForm.addEventListener('submit', function(e) {
            e.preventDefault();
            let isValid = true;
            
            const inputs = contactForm.querySelectorAll('input, textarea, select');
            inputs.forEach(function(input) {
                if (!validateField(input)) {
                    isValid = false;
                }
            });
            
            if (isValid) {
                const submitBtn = contactForm.querySelector('button[type="submit"]');
                if (submitBtn) {
                    const originalText = submitBtn.textContent;
                    submitBtn.disabled = true;
                    submitBtn.textContent = 'Sending...';
                    
                    setTimeout(function() {
                        submitBtn.textContent = 'Message Sent!';
                        submitBtn.style.backgroundColor = '#28a745';
                        contactForm.reset();
                        
                        setTimeout(function() {
                            submitBtn.disabled = false;
                            submitBtn.textContent = originalText;
                            submitBtn.style.backgroundColor = '';
                        }, 3000);
                    }, 1500);
                }
            }
        });
        
        contactForm.addEventListener('input', function(e) {
            const input = e.target.closest('input, textarea, select');
            if (input && input.classList.contains('input-error')) {
                validateField(input);
            }
        });
        
        contactForm.addEventListener('blur', function(e) {
            const input = e.target.closest('input, textarea, select');
            if (input) {
                validateField(input);
            }
        }, true);
    }

    // 4. Scroll animations (fade-in on scroll)
    const animatedElements = document.querySelectorAll('.fade-in, .fade-in-up, .fade-in-left, .fade-in-right');
    
    if (animatedElements.length > 0) {
        const observerOptions = {
            root: null,
            rootMargin: '0px 0px -50px 0px',
            threshold: 0.1
        };
        
        const observer = new IntersectionObserver(function(entries) {
            entries.forEach(function(entry) {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                    observer.unobserve(entry.target);
                }
            });
        }, observerOptions);
        
        animatedElements.forEach(function(el) {
            observer.observe(el);
        });
        
        const style = document.createElement('style');
        style.textContent = `
            .fade-in, .fade-in-up, .fade-in-left, .fade-in-right {
                opacity: 0;
                transition: opacity 0.6s ease-out, transform 0.6s ease-out;
            }
            .fade-in.visible {
                opacity: 1;
            }
            .fade-in-up {
                transform: translateY(30px);
            }
            .fade-in-up.visible {
                opacity: 1;
                transform: translateY(0);
            }
            .fade-in-left {
                transform: translateX(-30px);
            }
            .fade-in-left.visible {
                opacity: 1;
                transform: translateX(0);
            }
            .fade-in-right {
                transform: translateX(30px);
            }
            .fade-in-right.visible {
                opacity: 1;
                transform: translateX(0);
            }
        `;
        document.head.appendChild(style);
    }
});
