  // Helper to get localized e-commerce UI text
  // Tries zappyI18n first for multilingual support, falls back to static t object
  function getEcomText(key, fallback) {
    var lang = (getCurrentEcomLanguage() || '').split('-')[0].toLowerCase();
    if (ECOM_RUNTIME_TEXT[lang] && ECOM_RUNTIME_TEXT[lang][key]) {
      return ECOM_RUNTIME_TEXT[lang][key];
    }
    if (typeof zappyI18n !== 'undefined' && typeof zappyI18n.t === 'function') {
      var translated = zappyI18n.t('ecom_' + key);
      if (translated && translated !== 'ecom_' + key) {
        return translated;
      }
    }
    return fallback;
  }

  function getPreviewDashboardEcomText(key, fallback) {
    var dashboardLang = '';
    try {
      dashboardLang = new URLSearchParams(window.location.search).get('dashboardLang') || '';
    } catch (e) {}
    dashboardLang = String(dashboardLang || '').split('-')[0].toLowerCase();
    if (dashboardLang && ECOM_RUNTIME_TEXT[dashboardLang] && ECOM_RUNTIME_TEXT[dashboardLang][key]) {
      return ECOM_RUNTIME_TEXT[dashboardLang][key];
    }
    return getEcomText(key, fallback);
  }

  function getLocalizedCartItemName(item) {
    if (!item) return '';
    var lang = String(getCurrentEcomLanguage() || '').split('-')[0].toLowerCase();
    if (lang && item.name_translations && item.name_translations[lang]) {
      return item.name_translations[lang];
    }
    return item.name || '';
  }

  function escapeCartHtml(value) {
    return String(value == null ? '' : value).replace(/[&<>"']/g, function(c) {
      return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[c];
    });
  }

  function zappyIsDashboardPreview() {
    return window.location.pathname.indexOf('/preview-fullscreen/') !== -1;
  }

  var zappyStorefrontHasProductsCache;
  async function zappyHasAnyStorefrontProducts() {
    if (!zappyIsDashboardPreview()) return true;
    if (typeof zappyStorefrontHasProductsCache === 'boolean') {
      return zappyStorefrontHasProductsCache;
    }
    try {
      var res = await fetch(buildApiUrlWithLang('/api/ecommerce/storefront/products?websiteId=' + websiteId + '&limit=1'));
      var data = await res.json();
      zappyStorefrontHasProductsCache = !!(data && data.success && data.data && data.data.length > 0);
      return zappyStorefrontHasProductsCache;
    } catch (e) {
      console.warn('Failed to check storefront product count', e);
      zappyStorefrontHasProductsCache = true;
      return true;
    }
  }

  function zappyRenderPreviewEmptyStoreCta(message) {
    if (!zappyIsDashboardPreview()) {
      return '<div class="empty-cart">' + escapeCartHtml(message) + '</div>';
    }
    var title = getPreviewDashboardEcomText('previewEmptyStoreTitle', 'Your store is ready for products');
    var body = getPreviewDashboardEcomText('previewEmptyStoreBody', 'Add your first product in Store Manager to see it appear here.');
    var button = getPreviewDashboardEcomText('previewEmptyStoreButton', 'Add products');
    var badge = getPreviewDashboardEcomText('previewOnlyBadge', 'Preview only');
    var wrapStyle = 'box-sizing:border-box;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;width:min(92%,560px);margin:0 auto;padding:22px 24px;background:#fff;border:3px solid #ff0083;border-radius:18px;box-shadow:0 16px 38px rgba(255,0,131,.28);color:#111827;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;text-align:center;grid-column:1/-1;';
    var badgeStyle = 'display:inline-flex;align-items:center;border-radius:999px;background:#ffe6f3;color:#c00063;font-size:12px;font-weight:900;letter-spacing:.08em;line-height:1;padding:7px 12px;text-transform:uppercase;';
    var titleStyle = 'color:#111827;font-size:18px;font-weight:800;line-height:1.25;margin:0;';
    var bodyStyle = 'color:#4b5563;font-size:14px;line-height:1.5;margin:0;max-width:460px;';
    var buttonStyle = 'appearance:none;display:inline-flex;align-items:center;justify-content:center;min-height:52px;margin-top:4px;padding:0 30px;border:0;border-radius:999px;background:linear-gradient(135deg,#ff0083,#7c3aed);box-shadow:0 12px 26px rgba(255,0,131,.34);color:#fff;cursor:pointer;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;font-size:16px;font-weight:900;line-height:1;text-decoration:none;';
    return '<div class="empty-cart zappy-preview-empty-store-cta" style="' + wrapStyle + '">' +
      '<div class="zappy-preview-empty-store-badge" style="' + badgeStyle + '">' + escapeCartHtml(badge) + '</div>' +
      '<div class="zappy-preview-empty-store-title" style="' + titleStyle + '">' + escapeCartHtml(title) + '</div>' +
      '<p style="' + bodyStyle + '">' + escapeCartHtml(body) + '</p>' +
      '<button type="button" class="zappy-preview-open-store-manager" style="' + buttonStyle + '" onclick="window.parent && window.parent.postMessage({ type: \'ZAPPY_OPEN_STORE_MANAGER\', section: \'products\' }, \'*\')">' +
        '＋ ' + escapeCartHtml(button) +
      '</button>' +
    '</div>';
  }
  
  
// Helper to strip HTML tags and convert rich text to plain text for card previews
function stripHtmlToText(html) {
  if (!html) return '';
  // Create a temporary element to parse HTML
  var temp = document.createElement('div');
  temp.innerHTML = html;
  // Replace block-level elements' closing tags with space to preserve word boundaries
  // This handles </p>, </div>, </li>, <br>, etc. from rich text editors
  temp.innerHTML = temp.innerHTML
    .replace(/<\/p>/gi, ' ')
    .replace(/<\/div>/gi, ' ')
    .replace(/<\/li>/gi, ' ')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/h[1-6]>/gi, ' ');
  // Get text content (strips remaining HTML tags)
  var text = temp.textContent || temp.innerText || '';
  // Normalize whitespace (replace multiple spaces/newlines with single space)
  text = text.replace(/\s+/g, ' ').trim();
  return text;
}

  
  // RTL detection must follow the active runtime language, not only the generated source language.
  const isRTL = isCurrentEcomRTL();
  
  // Cart state
  let cart = JSON.parse(localStorage.getItem('zappy_cart_' + websiteId) || '[]');
  
  // VAT rate - fetched from store settings, with fallback to default
  let vatRate = 0.18; // Default fallback (Israel VAT rate as of January 2025)
  let productLayout = 'standard'; // Default product card layout
  let storeSettingsFetched = false;
  let sidebarFiltersConfig = {};
  let sortingConfig = {};
  let viewToggleEnabled = true;
  let currentSortKey = 'popularity';
  let currentViewMode = localStorage.getItem('zappy_view_mode_' + websiteId) || 'grid';
  let activeSidebarFilters = { categories: [], brands: [], tags: [], priceMin: null, priceMax: null, sale: false };
  let storeCountry = null;
  let minimumOrderAmount = null;

  // Fetch store settings (including tax rate and product layout) from API
  async function fetchStoreSettings() {
    if (storeSettingsFetched) return;
    try {
      const res = await fetch(buildApiUrlWithLang('/api/ecommerce/storefront/settings?websiteId=' + websiteId));
      const data = await res.json();
      if (data.success && data.data) {
        if (data.data.taxRate && data.data.taxRate > 0) {
          vatRate = data.data.taxRate;
        }
        // Keep the baked multi-currency config fresh (e.g. after a settings save
        // in preview) so language switches re-price against the latest rates.
        if (data.data.multiCurrency && typeof data.data.multiCurrency === 'object') {
          ZAPPY_MULTI_CURRENCY = data.data.multiCurrency;
          try { window.ZAPPY_MULTI_CURRENCY = ZAPPY_MULTI_CURRENCY; } catch (e) {}
        }
        if (data.data.productLayout) {
          productLayout = data.data.productLayout;
        }
        if (data.data.sidebarFiltersConfig) {
          sidebarFiltersConfig = data.data.sidebarFiltersConfig;
        }
        if (data.data.sortingConfig) {
          sortingConfig = data.data.sortingConfig;
        }
        if (data.data.viewToggleEnabled != null) {
          viewToggleEnabled = data.data.viewToggleEnabled;
        }
        if (data.data.country) {
          storeCountry = data.data.country;
        }
        minimumOrderAmount = (data.data.minimumOrderAmount && data.data.minimumOrderAmount > 0)
          ? parseFloat(data.data.minimumOrderAmount)
          : null;
        updateMinimumOrderBanner();
        updatePlaceOrderState();
        var catalogMenu = document.getElementById('zappy-catalog-menu');
        if (catalogMenu) {
          if (data.data.catalogMenuEnabled === true) {
            catalogMenu.style.removeProperty('display');
          } else {
            catalogMenu.style.setProperty('display', 'none', 'important');
          }
          if (typeof setupFixedHeaders === 'function') {
            setTimeout(setupFixedHeaders, 50);
          }
        }
        storeSettingsFetched = true;
      }
    } catch (e) {
      console.warn('Failed to fetch store settings, using defaults:', e);
    }
  }
  
  // Fetch settings on page load
