function getEcomText(key, fallback) {
  var lang = '';
  if (typeof zappyI18n !== 'undefined' && typeof zappyI18n.getCurrentLanguage === 'function') {
    lang = zappyI18n.getCurrentLanguage() || '';
  }
  if (!lang) {
    lang = document.documentElement.lang || '';
  }
  if (!lang) {
    try { lang = localStorage.getItem('zappy_lang') || ''; } catch (e) {}
  }
  lang = String(lang).split('-')[0].toLowerCase();
  if (ECOM_RUNTIME_TEXT[lang] && ECOM_RUNTIME_TEXT[lang][key]) {
    return ECOM_RUNTIME_TEXT[lang][key];
  }
  if (typeof zappyI18n !== 'undefined' && typeof zappyI18n.t === 'function') {
    var translated = zappyI18n.t('ecom_' + key);
    if (translated && translated !== 'ecom_' + key) {
      return translated;
    }
  }
  return fallback;
}

function getPreviewDashboardEcomText(key, fallback) {
  var dashboardLang = '';
  try {
    dashboardLang = new URLSearchParams(window.location.search).get('dashboardLang') || '';
  } catch (e) {}
  dashboardLang = String(dashboardLang || '').split('-')[0].toLowerCase();
  if (dashboardLang && ECOM_RUNTIME_TEXT[dashboardLang] && ECOM_RUNTIME_TEXT[dashboardLang][key]) {
    return ECOM_RUNTIME_TEXT[dashboardLang][key];
  }
  return getEcomText(key, fallback);
}

function zappyPreviewCtaEscHtml(value) {
  return String(value == null ? '' : value).replace(/[&<>"']/g, function(c) {
    return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[c];
  });
}

function zappyIsDashboardPreview() {
  return window.location.pathname.indexOf('/preview-fullscreen/') !== -1;
}

var zappyStorefrontHasProductsCache;
async function zappyHasAnyStorefrontProducts() {
  var websiteId = window.ZAPPY_WEBSITE_ID;
  if (!zappyIsDashboardPreview()) return true;
  if (!websiteId) return true;
  if (typeof zappyStorefrontHasProductsCache === 'boolean') {
    return zappyStorefrontHasProductsCache;
  }
  try {
    var res = await fetch(buildApiUrlWithLang('/api/ecommerce/storefront/products?websiteId=' + websiteId + '&limit=1'));
    var data = await res.json();
    zappyStorefrontHasProductsCache = !!(data && data.success && data.data && data.data.length > 0);
    return zappyStorefrontHasProductsCache;
  } catch (e) {
    console.warn('Failed to check storefront product count', e);
    zappyStorefrontHasProductsCache = true;
    return true;
  }
}

function zappyRenderPreviewEmptyStoreCta(message, wrapperClass) {
  var cls = wrapperClass || 'empty-cart';
  if (!zappyIsDashboardPreview()) {
    return '<div class="' + cls + '">' + zappyPreviewCtaEscHtml(message) + '</div>';
  }
  var title = getPreviewDashboardEcomText('previewEmptyStoreTitle', 'Your store is ready for products');
  var body = getPreviewDashboardEcomText('previewEmptyStoreBody', 'Add your first product in Store Manager to see it appear here.');
  var button = getPreviewDashboardEcomText('previewEmptyStoreButton', 'Add products');
  var badge = getPreviewDashboardEcomText('previewOnlyBadge', 'Preview only');
  var wrapStyle = 'box-sizing:border-box;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;width:min(92%,560px);margin:0 auto;padding:22px 24px;background:#fff;border:3px solid #ff0083;border-radius:18px;box-shadow:0 16px 38px rgba(255,0,131,.28);color:#111827;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;text-align:center;grid-column:1/-1;';
  var badgeStyle = 'display:inline-flex;align-items:center;border-radius:999px;background:#ffe6f3;color:#c00063;font-size:12px;font-weight:900;letter-spacing:.08em;line-height:1;padding:7px 12px;text-transform:uppercase;';
  var titleStyle = 'color:#111827;font-size:18px;font-weight:800;line-height:1.25;margin:0;';
  var bodyStyle = 'color:#4b5563;font-size:14px;line-height:1.5;margin:0;max-width:460px;';
  var buttonStyle = 'appearance:none;display:inline-flex;align-items:center;justify-content:center;min-height:52px;margin-top:4px;padding:0 30px;border:0;border-radius:999px;background:linear-gradient(135deg,#ff0083,#7c3aed);box-shadow:0 12px 26px rgba(255,0,131,.34);color:#fff;cursor:pointer;font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;font-size:16px;font-weight:900;line-height:1;text-decoration:none;';
  return '<div class="' + cls + ' zappy-preview-empty-store-cta" style="' + wrapStyle + '">' +
    '<div class="zappy-preview-empty-store-badge" style="' + badgeStyle + '">' + zappyPreviewCtaEscHtml(badge) + '</div>' +
    '<div class="zappy-preview-empty-store-title" style="' + titleStyle + '">' + zappyPreviewCtaEscHtml(title) + '</div>' +
    '<p style="' + bodyStyle + '">' + zappyPreviewCtaEscHtml(body) + '</p>' +
    '<button type="button" class="zappy-preview-open-store-manager" style="' + buttonStyle + '" onclick="window.parent && window.parent.postMessage({ type: \'ZAPPY_OPEN_STORE_MANAGER\', section: \'products\' }, \'*\')">' +
      '＋ ' + zappyPreviewCtaEscHtml(button) +
    '</button>' +
  '</div>';
}

// Helper to strip HTML tags - defined here since ecommerceJs uses an IIFE and its scope is not accessible

// Helper to strip HTML tags and convert rich text to plain text for card previews
function stripHtmlToText(html) {
  if (!html) return '';
  // Create a temporary element to parse HTML
  var temp = document.createElement('div');
  temp.innerHTML = html;
  // Replace block-level elements' closing tags with space to preserve word boundaries
  // This handles </p>, </div>, </li>, <br>, etc. from rich text editors
  temp.innerHTML = temp.innerHTML
    .replace(/<\/p>/gi, ' ')
    .replace(/<\/div>/gi, ' ')
    .replace(/<\/li>/gi, ' ')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/h[1-6]>/gi, ' ');
  // Get text content (strips remaining HTML tags)
  var text = temp.textContent || temp.innerText || '';
  // Normalize whitespace (replace multiple spaces/newlines with single space)
  text = text.replace(/\s+/g, ' ').trim();
  return text;
}

function zappyApplyCustomerPercentToPrice(basePrice, productId) {
  function applyFromWindowConfig() {
    var cfg = window.__zappyCustomerDiscountConfig;
    if (!cfg || !cfg.discountPercent || !Number.isFinite(basePrice) || basePrice <= 0) {
      return { price: basePrice, applied: false };
    }
    var excluded = cfg.excludedProductIds || [];
    if (excluded.indexOf(productId) !== -1) return { price: basePrice, applied: false };
    var discounted = basePrice - (basePrice * parseFloat(cfg.discountPercent) / 100);
    if (!Number.isFinite(discounted) || discounted >= basePrice) {
      return { price: basePrice, applied: false };
    }
    return { price: discounted, applied: true, originalPrice: basePrice };
  }

  if (typeof window.__zappyApplyCustomerPercentToPrice === 'function') {
    var delegated = window.__zappyApplyCustomerPercentToPrice(basePrice, productId);
    if (delegated.applied) return delegated;
    if (window.__zappyCustomerDiscountConfig && window.__zappyCustomerDiscountConfig.discountPercent > 0) {
      return applyFromWindowConfig();
    }
    return delegated;
  }
  return applyFromWindowConfig();
}

function zappyHasActiveCustomerDiscount() {
  if (typeof window.__zappyHasActiveCustomerDiscountCfg === 'function') {
    return window.__zappyHasActiveCustomerDiscountCfg();
  }
  var cfg = window.__zappyCustomerDiscountConfig;
  return !!(cfg && parseFloat(cfg.discountPercent) > 0);
}

async function syncProductDetailCustomerDiscount() {
  if (!document.getElementById('product-detail') || !window.currentProduct) return;
  if (window.__zappyCustomerDiscountConfig && window.__zappyCustomerDiscountConfig.discountPercent > 0) {
    if (typeof window.__zappyUpdateVariantUI === 'function' && window.productTranslations) {
      window.__zappyUpdateVariantUI(window.selectedVariant || null, window.currentProduct, window.productTranslations, {});
    }
    return;
  }
  if (typeof window.__zappyFetchCustomerDiscount === 'function') {
    await window.__zappyFetchCustomerDiscount();
    if (typeof window.__zappyUpdateVariantUI === 'function' && window.productTranslations) {
      window.__zappyUpdateVariantUI(window.selectedVariant || null, window.currentProduct, window.productTranslations, {});
    }
  }
}

function renderProductGrid(grid, products, t, isFeaturedSection, viewMode) {
  // Card layout is now Standard (square) or Portrait (tall); legacy
  // compact/detailed map to standard.
  var layout = (additionalJsProductLayout === 'portrait') ? 'portrait' : 'standard';
  if (!isFeaturedSection) {
    var viewClass = (viewMode === 'list') ? ' view-list' : '';
    grid.className = 'product-grid layout-' + layout + viewClass;
    grid.setAttribute('data-zappy-auto-grid', 'true');
  }
  
  // Get localized text for UI elements
  var localizedAddToCart = getEcomText('addToCart', t.addToCart);
  var localizedViewDetails = getEcomText('viewDetails', t.viewDetails);
  
  grid.innerHTML = products.map(p => {
    // Check if price should be displayed (default to true if not set)
    const showPrice = p.custom_fields?.showPrice !== false;
    const hasSalePrice = p.sale_price && parseFloat(p.sale_price) < parseFloat(p.price);
    const variantCount = parseInt(p.variant_count || 0, 10);
    const variantPriceCount = parseInt(p.variant_price_count || 0, 10);
    const variantMinPrice = parseFloat(p.variant_min_price);
    const variantMaxPrice = parseFloat(p.variant_max_price);
    const hasVariantPriceRange = variantCount > 1 && variantPriceCount > 1 && Number.isFinite(variantMinPrice) && Number.isFinite(variantMaxPrice) && variantMinPrice !== variantMaxPrice;
    const startingAtLabel = getEcomText('startingAt', t.startingAt || 'Starting at');

    // Check for seasonal discount on this product
    var seasonalD = typeof getSeasonalDiscountForProduct === 'function' ? getSeasonalDiscountForProduct(p.id) : null;
    var effectivePrice = parseFloat(p.price);
    var effectiveSalePrice = hasSalePrice ? parseFloat(p.sale_price) : null;
    var displayOriginalPrice = effectivePrice;
    var seasonalApplied = false;

    if (seasonalD && !hasVariantPriceRange) {
      var basePrice = effectiveSalePrice !== null ? effectiveSalePrice : effectivePrice;
      var discountedPrice = basePrice;
      if (seasonalD.type === 'percentage') {
        discountedPrice = basePrice - (basePrice * parseFloat(seasonalD.value) / 100);
      } else if (seasonalD.type === 'fixed') {
        discountedPrice = Math.max(0, basePrice - parseFloat(seasonalD.value));
      }
      if (discountedPrice < basePrice) {
        seasonalApplied = true;
        displayOriginalPrice = basePrice;
        effectiveSalePrice = discountedPrice;
      }
    }

    if (zappyHasActiveCustomerDiscount() && !hasVariantPriceRange) {
      var custBase = effectiveSalePrice !== null ? effectiveSalePrice : effectivePrice;
      var custAdj = zappyApplyCustomerPercentToPrice(custBase, p.id);
      if (custAdj.applied) {
        displayOriginalPrice = custBase;
        effectiveSalePrice = custAdj.price;
        seasonalApplied = true;
      }
    }

    var displayPrice;
    if (!showPrice) {
      displayPrice = '';
    } else if (hasVariantPriceRange) {
      var variantDisplayMin = variantMinPrice;
      if (zappyHasActiveCustomerDiscount()) {
        var custAdjRange = zappyApplyCustomerPercentToPrice(variantMinPrice, p.id);
        if (custAdjRange.applied) {
          variantDisplayMin = custAdjRange.price;
          displayPrice = startingAtLabel + ' ' + formatMoney(variantDisplayMin) + ' <span class="original-price">' + formatMoney(variantMinPrice) + '</span>';
        } else {
          displayPrice = startingAtLabel + ' ' + formatMoney(variantMinPrice);
        }
      } else {
        displayPrice = startingAtLabel + ' ' + formatMoney(variantMinPrice);
      }
    } else if (seasonalApplied && effectiveSalePrice !== null) {
      displayPrice = formatMoney(effectiveSalePrice) + ' <span class="original-price">' + formatMoney(displayOriginalPrice) + '</span>';
    } else if (hasSalePrice) {
      displayPrice = formatMoney(parseFloat(p.sale_price)) + ' <span class="original-price">' + formatMoney(parseFloat(p.price)) + '</span>';
    } else {
      displayPrice = formatMoney(parseFloat(p.price));
    }
    
    // Get first image with correct URL in preview/live
    var imageUrl = p.images && p.images[0]
      ? (window.resolveProductImageUrl ? window.resolveProductImageUrl(p.images[0]) : p.images[0])
      : '';
    
    // Build tag badges (manual only - all tags come from product.tags array)
    var tagBadges = [];
    if (p.tags && p.tags.length) {
      p.tags.forEach(function(tag) {
        var tagLower = tag.toLowerCase();
        // Apply special styling for known tag types
        if (tagLower === 'sale' || tagLower === 'מבצע') {
          tagBadges.push('<span class="product-tag tag-sale">' + tag + '</span>');
        } else if (tagLower === 'new' || tagLower === 'חדש') {
          tagBadges.push('<span class="product-tag tag-new">' + tag + '</span>');
        } else if (tagLower === 'featured' || tagLower === 'מומלץ') {
          tagBadges.push('<span class="product-tag tag-featured">' + tag + '</span>');
        } else {
          tagBadges.push('<span class="product-tag">' + tag + '</span>');
        }
      });
    }
    var tagsHtml = tagBadges.length > 0 ? '<div class="product-tags">' + tagBadges.join('') + '</div>' : '';
    
    // Build card content
    var imageHtml = imageUrl ? '<img src="' + imageUrl + '" alt="' + p.name + '">' : '<div class="no-image-placeholder">📦</div>';
    
    // Only include price div if showPrice is true
    var pricePerUnitHtml = getPricePerUnitHtml(p);
    var priceHtml = showPrice ? '<div class="price">' + displayPrice + '</div>' + pricePerUnitHtml : '';
    
    var favBtnHtml = isCatalogMode ? '' : '<button type="button" class="card-favorite-btn" data-product-id="' + p.id + '" onclick="event.preventDefault(); event.stopPropagation(); toggleCardFavorite(this, \'' + p.id + '\')" title="שמור למועדפים" aria-pressed="false"><svg class="heart-outline" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 20 18.3" fill="none"><path d="M14.7917 0C12.705 0 10.8108 1.5425 10 3.62833C9.18917 1.54167 7.295 0 5.20833 0C2.33667 0 0 2.33667 0 5.20833C0 10.8417 8.12833 16.9333 9.7575 18.0967L10 18.27L10.2425 18.0967C11.8725 16.9333 20 10.8408 20 5.20833C20 2.33667 17.6633 0 14.7917 0ZM10 17.2442C5.71583 14.1317 0.833333 9.185 0.833333 5.20833C0.833333 2.79583 2.79583 0.833333 5.20833 0.833333C7.49833 0.833333 9.58333 3.21667 9.58333 5.83333H10.4167C10.4167 3.21667 12.5017 0.833333 14.7917 0.833333C17.2042 0.833333 19.1667 2.79583 19.1667 5.20833C19.1667 9.185 14.2842 14.1317 10 17.2442Z" fill="currentColor"/></svg><svg class="heart-filled" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 20 18.3"><path d="M14.7917 0C12.705 0 10.8108 1.5425 10 3.62833C9.18917 1.54167 7.295 0 5.20833 0C2.33667 0 0 2.33667 0 5.20833C0 10.8417 8.12833 16.9333 9.7575 18.0967L10 18.27L10.2425 18.0967C11.8725 16.9333 20 10.8408 20 5.20833C20 2.33667 17.6633 0 14.7917 0Z" fill="#e74c3c"/></svg></button>';
    var productHref = buildStorefrontPath('/courses/' + (p.slug || p.id));

    // Register the product + assemble via the shared card builder.
    window.zappyRegisterCardProduct(p);
    var cardContent = window.zappyBuildCardInnerHtml(p, layout, {
      imageHtml: imageHtml,
      tagsHtml: tagsHtml,
      favBtnHtml: favBtnHtml,
      productHref: productHref,
      priceHtml: priceHtml,
      shortDesc: stripHtmlToText(p.short_description || ''),
      isCatalogMode: isCatalogMode,
      localizedViewDetails: localizedViewDetails
    });

    return '<div class="product-card ' + layout + '" data-product-id="' + p.id + '">' + cardContent + '</div>';
  }).join('');

  window.zappyAfterCardsRendered(grid);
}

// Load categories into catalog dropdown, respecting parent/child hierarchy
function isCatalogRootHref(href) {
  if (!href) return false;
  var path = href.split('?')[0].split('#')[0];
  if (path.length > 1 && path.endsWith('/')) path = path.slice(0, -1);
  return path === '/products' || path === '/courses'
    || /\/(?:[a-z]{2}\/)?(?:products|courses)$/.test(path);
}

function getNavCategoryLinksContainer() {
  var navList = document.getElementById('zappy-nav-category-links');
  if (navList) return navList;

  var dropdown = document.querySelector('.zappy-products-dropdown');
  if (dropdown) {
    var sub = dropdown.querySelector(':scope > .sub-menu, :scope > ul.sub-menu');
    if (sub) {
      if (!sub.id) sub.id = 'zappy-nav-category-links';
      return sub;
    }
  }

  var roots = document.querySelectorAll(
    '.nav-menu > li.menu-item-has-children, .nav-menu > li.zappy-products-dropdown, nav .nav-menu > li.menu-item-has-children'
  );
  for (var i = 0; i < roots.length; i++) {
    var li = roots[i];
    var trigger = li.querySelector(':scope > a');
    if (!trigger || !isCatalogRootHref(trigger.getAttribute('href'))) continue;
    var subMenu = li.querySelector(':scope > .sub-menu, :scope > ul.sub-menu');
    if (!subMenu) continue;
    if (!li.classList.contains('zappy-products-dropdown')) {
      li.classList.add('zappy-products-dropdown', 'menu-item-has-children');
    }
    if (!subMenu.id) subMenu.id = 'zappy-nav-category-links';
    return subMenu;
  }
  return null;
}

function initMobileProductsDropdown() {
  if (window.innerWidth > 768) return;
  var dropdown = document.querySelector('.zappy-products-dropdown');
  if (!dropdown) {
    var navList = getNavCategoryLinksContainer();
    if (navList) dropdown = navList.closest('li');
  }
  if (!dropdown || dropdown.__zappyMobileProductsBound) return;
  var submenu = dropdown.querySelector(':scope > .sub-menu') || document.getElementById('zappy-nav-category-links');
  var trigger = dropdown.querySelector(':scope > a');
  if (!submenu || !trigger) return;

  dropdown.__zappyMobileProductsBound = true;
  function hasLoadedCategories() {
    return !!submenu.querySelector('li[data-category-id]');
  }

  async function ensureCategoriesLoaded() {
    if (hasLoadedCategories() || submenu.__zappyCategoriesLoading) return;
    if (typeof window.loadCatalogCategories !== 'function') return;
    submenu.__zappyCategoriesLoading = true;
    try {
      await window.loadCatalogCategories();
    } catch (err) {
      // Keep the existing All Products link available if loading fails.
    } finally {
      submenu.__zappyCategoriesLoading = false;
    }
  }

  async function toggle(e) {
    if (window.innerWidth > 768) return;
    e.preventDefault();
    e.stopPropagation();
    if (typeof e.stopImmediatePropagation === 'function') e.stopImmediatePropagation();
    if (!submenu.classList.contains('mobile-expanded')) {
      await ensureCategoriesLoaded();
    }
    submenu.classList.toggle('mobile-expanded');
    var button = dropdown.querySelector('.mobile-submenu-toggle');
    if (button) button.classList.toggle('expanded', submenu.classList.contains('mobile-expanded'));
  }

  var button = dropdown.querySelector('.mobile-submenu-toggle');
  if (button && !button.__zappyMobileProductsToggleBound) {
    button.__zappyMobileProductsToggleBound = true;
    button.addEventListener('click', toggle, true);
  }
  trigger.addEventListener('click', function(e) {
    if (submenu.classList.contains('mobile-expanded')) return;
    toggle(e);
  }, true);
}

async function loadCatalogCategories() {
    const list = document.getElementById('zappy-category-links');
    const navList = getNavCategoryLinksContainer();
    if (!list && !navList) return;
  var websiteId = window.ZAPPY_WEBSITE_ID;
  if (!websiteId) return;
  var currentDir = isCurrentLanguageRTL() ? 'rtl' : 'ltr';
  var catalogMenu = document.getElementById('zappy-catalog-menu');
  if (catalogMenu) {
    catalogMenu.setAttribute('dir', currentDir);
    catalogMenu.classList.toggle('rtl', currentDir === 'rtl');
    catalogMenu.classList.toggle('ltr', currentDir === 'ltr');
  }
  [list, navList].forEach(function(menuList) {
    if (!menuList) return;
    menuList.setAttribute('dir', currentDir);
    menuList.style.setProperty('direction', currentDir, 'important');
  });
  
  try {
    var res = await fetch(buildApiUrlWithLang('/api/ecommerce/storefront/categories?websiteId=' + websiteId));
    var data = await res.json();
    if (!data.success || !data.data?.length) {
      collapseEmptyProductsDropdown();
      return;
    }

    var allCats = data.data;
    var childrenMap = {};
    var topLevel = [];
    allCats.forEach(function(cat) {
      if (cat.parent_id) {
        if (!childrenMap[cat.parent_id]) childrenMap[cat.parent_id] = [];
        childrenMap[cat.parent_id].push(cat);
      } else {
        topLevel.push(cat);
      }
    });

    // Flatten descendants so grandchildren+ appear under their top-level ancestor
    function collectDescendants(parentId) {
      var result = [];
      var direct = childrenMap[parentId] || [];
      direct.forEach(function(child) {
        result.push(child);
        result = result.concat(collectDescendants(child.id));
      });
      return result;
    }
    topLevel.forEach(function(cat) {
      childrenMap[cat.id] = collectDescendants(cat.id);
    });

    function catUrl(cat) { return buildStorefrontPath('/category/' + (cat.slug || cat.id)); }
    var chevronSvg = '<svg class="catalog-menu-chevron" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"></polyline></svg>';

    // Keep the merchant-authored category order stable across languages.
    var orderedTopLevel = topLevel;

    // Build HTML for the main nav dropdown (flat list with parent/child classes)
    var dropdownItemsHtml = orderedTopLevel.map(function(cat) {
      var children = childrenMap[cat.id] || [];
      if (children.length === 0) {
        return '<li data-category-id="' + cat.id + '" data-category-slug="' + (cat.slug || '') + '"><a href="' + catUrl(cat) + '" dir="' + currentDir + '">' + cat.name + '</a></li>';
      }
      var items = '<li class="zappy-nav-parent" data-category-id="' + cat.id + '" data-category-slug="' + (cat.slug || '') + '"><a href="' + catUrl(cat) + '" dir="' + currentDir + '">' + cat.name + '</a></li>';
      children.forEach(function(child) {
        items += '<li class="zappy-nav-child" data-category-id="' + child.id + '" data-category-slug="' + (child.slug || '') + '"><a href="' + catUrl(child) + '" dir="' + currentDir + '">' + child.name + '</a></li>';
      });
      return items;
    }).join('');

    // Build HTML for the secondary catalog bar (flat links / dropdowns)
    var barItemsHtml = orderedTopLevel.map(function(cat) {
      var children = childrenMap[cat.id] || [];
      if (children.length === 0) {
        return '<a href="' + catUrl(cat) + '" class="catalog-menu-item" data-category-id="' + cat.id + '" data-category-slug="' + (cat.slug || '') + '" dir="' + currentDir + '">' + cat.name + '</a>';
      }
      var subLinks = children.map(function(child) {
        return '<a href="' + catUrl(child) + '" class="catalog-menu-item" data-category-id="' + child.id + '" data-category-slug="' + (child.slug || '') + '" dir="' + currentDir + '">' + child.name + '</a>';
      }).join('');
      return '<div class="catalog-menu-parent" data-category-id="' + cat.id + '" data-category-slug="' + (cat.slug || '') + '">' +
        '<a href="' + catUrl(cat) + '" class="catalog-menu-item catalog-menu-trigger" dir="' + currentDir + '">' + cat.name + ' ' + chevronSvg + '</a>' +
        '<div class="sub-menu" dir="' + currentDir + '">' + subLinks + '</div>' +
      '</div>';
    }).join('');

    if (navList) {
      navList.querySelectorAll('li[data-category-id]').forEach(function(node) { node.remove(); });
      navList.insertAdjacentHTML('beforeend', dropdownItemsHtml);
      setTimeout(initMobileProductsDropdown, 0);
    }

    if (list) {
      list.querySelectorAll('[data-category-id]').forEach(function(node) { node.remove(); });
      list.insertAdjacentHTML('beforeend', barItemsHtml);
    }
  } catch (e) {
    console.error('Failed to load categories', e);
  }
  collapseEmptyProductsDropdown();
  setTimeout(initMobileProductsDropdown, 0);
}

// When the nav dropdown has zero visible items (showAllProducts hidden + no categories),
// convert it from a dropdown into a plain link so it doesn't render as an empty menu.
function collapseEmptyProductsDropdown() {
  var dropdown = document.querySelector('.zappy-products-dropdown');
  var collapsed = document.querySelector('[data-zappy-products-collapsed]');
  var el = dropdown || collapsed;
  if (!el) {
    var navList = getNavCategoryLinksContainer();
    if (navList) {
      el = navList.closest('li');
      dropdown = el;
    }
  }
  if (!el) return;
  var navList = el.querySelector('#zappy-nav-category-links') || document.getElementById('zappy-nav-category-links');
  if (!navList) return;

  var items = navList.querySelectorAll('li');
  var hasVisible = false;
  for (var i = 0; i < items.length; i++) {
    if (items[i].style.display !== 'none') { hasVisible = true; break; }
  }

  if (!hasVisible && dropdown) {
    dropdown.classList.remove('menu-item-has-children', 'zappy-products-dropdown');
    el.setAttribute('data-zappy-products-collapsed', 'true');
    var arrow = el.querySelector('.dropdown-arrow');
    if (arrow) arrow.style.display = 'none';
    var subMenu = el.querySelector('.sub-menu, #zappy-nav-category-links');
    if (subMenu) subMenu.style.setProperty('display', 'none', 'important');
  } else if (hasVisible && collapsed) {
    collapsed.classList.add('menu-item-has-children', 'zappy-products-dropdown');
    collapsed.removeAttribute('data-zappy-products-collapsed');
    var arrow2 = collapsed.querySelector('.dropdown-arrow');
    if (arrow2) arrow2.style.display = '';
    var subMenu2 = collapsed.querySelector('.sub-menu, #zappy-nav-category-links');
    if (subMenu2) subMenu2.style.removeProperty('display');
  }
}

// Hide sub-navbars (catalog menu & announcement bar) on focused pages
// Product detail, checkout, and order pages hide these so the user can focus on the task
function handleSubNavbarVisibility() {
  var pagePath = window.location.pathname;
  var urlParams = new URLSearchParams(window.location.search);
  var pageParam = urlParams.get('page');
  if (pageParam) pagePath = pageParam;
  pagePath = pagePath.toLowerCase();

  var isCheckoutPage = pagePath.indexOf('/checkout') !== -1;

  var isFocusedPage = (
    pagePath.indexOf('/product/') !== -1 ||
    pagePath === '/product' ||
    pagePath.indexOf('/cart') !== -1 ||
    isCheckoutPage ||
    pagePath.indexOf('/order-success') !== -1 ||
    pagePath.indexOf('/order') !== -1
  );

  document.body.classList.toggle('zappy-focused-page', isFocusedPage);
  document.body.classList.toggle('zappy-checkout-page', isCheckoutPage);

  if (isFocusedPage) {
    var catalogMenu = document.getElementById('zappy-catalog-menu');
    var announcementBar = document.querySelector('.zappy-announcement-bar');
    if (catalogMenu) catalogMenu.style.setProperty('display', 'none', 'important');
    if (announcementBar) announcementBar.style.setProperty('display', 'none', 'important');

    // Recalculate header positioning since hidden bars have 0 height now
    if (typeof setupFixedHeaders === 'function') {
      setTimeout(setupFixedHeaders, 50);
    }
  } else {
    var catalogMenuShown = document.getElementById('zappy-catalog-menu');
    var announcementBarShown = document.querySelector('.zappy-announcement-bar');
    if (catalogMenuShown) catalogMenuShown.style.removeProperty('display');
    if (announcementBarShown) announcementBarShown.style.removeProperty('display');
  }
}

// Transparent navbar scroll effect — frosted glass on scroll
// Activates only when --nav-bg is 'transparent' (set by navbar customization)
function initTransparentNavbarScrollEffect() {
  var nb = document.querySelector('nav.navbar, .navbar:not(.zappy-catalog-menu)');
  if (!nb) return;
  var cs = getComputedStyle(nb);
  var bgc = cs.backgroundColor;
  // Check if navbar background is transparent (rgba(0,0,0,0) or 'transparent')
  var isTransparent = bgc === 'transparent' || bgc === 'rgba(0, 0, 0, 0)';
  if (!isTransparent) return;

  var cm = document.querySelector('.zappy-catalog-menu');
  // Determine frosted glass color from the page background
  var bodyBg = getComputedStyle(document.body).backgroundColor || 'rgb(255,255,255)';
  var m = bodyBg.match(/\d+/g);
  var r = m ? parseInt(m[0]) : 0, g = m ? parseInt(m[1]) : 0, b = m ? parseInt(m[2]) : 0;
  var frostedBg = 'rgba(' + r + ',' + g + ',' + b + ',0.85)';
  var threshold = 60;

  // Determine correct text color for the frosted glass background via luminance
  var sR = r / 255, sG = g / 255, sB = b / 255;
  sR = sR <= 0.03928 ? sR / 12.92 : Math.pow((sR + 0.055) / 1.055, 2.4);
  sG = sG <= 0.03928 ? sG / 12.92 : Math.pow((sG + 0.055) / 1.055, 2.4);
  sB = sB <= 0.03928 ? sB / 12.92 : Math.pow((sB + 0.055) / 1.055, 2.4);
  var frostedLum = 0.2126 * sR + 0.7152 * sG + 0.0722 * sB;
  var frostedIsLight = frostedLum > 0.4;
  var rootStyle = getComputedStyle(document.documentElement);
  var textDark = rootStyle.getPropertyValue('--text-dark').trim() || '#1a1a1a';
  var textLight = rootStyle.getPropertyValue('--text-light').trim() || '#ffffff';
  var scrolledTextColor = frostedIsLight ? textDark : textLight;

  nb.style.transition = 'background 0.3s ease, backdrop-filter 0.3s ease, -webkit-backdrop-filter 0.3s ease, box-shadow 0.3s ease';
  if (cm) cm.style.transition = 'background 0.3s ease, backdrop-filter 0.3s ease, -webkit-backdrop-filter 0.3s ease';

  var navElSelector = 'a, .navbar-brand, .navbar-brand a, .dropdown-toggle, .mobile-toggle, .phone-header-btn, .mobile-hamburger-btn, .mobile-close-btn, .mobile-submenu-toggle, .nav-link';
  var skipClasses = ['cart-link', 'login-link', 'nav-search-toggle', 'search-toggle'];

  function setScrolledColors(container, color) {
    var els = container.querySelectorAll(navElSelector);
    for (var i = 0; i < els.length; i++) {
      var skip = false;
      for (var j = 0; j < skipClasses.length; j++) {
        if (els[i].classList.contains(skipClasses[j])) { skip = true; break; }
      }
      if (!skip) els[i].style.setProperty('color', color, 'important');
    }
  }

  function clearScrolledColors(container) {
    var els = container.querySelectorAll(navElSelector);
    for (var i = 0; i < els.length; i++) els[i].style.removeProperty('color');
  }

  function onScroll() {
    if (window._zappyNavOverrideActive) return;
    if (window.innerWidth <= 768) {
      nb.style.removeProperty('background');
      nb.style.removeProperty('background-color');
      nb.style.removeProperty('background-image');
      nb.style.removeProperty('--frosted-text');
      nb.style.backdropFilter = '';
      nb.style.webkitBackdropFilter = '';
      nb.style.boxShadow = '';
      nb.classList.remove('scrolled');
      clearScrolledColors(nb);
      if (cm) {
        cm.style.removeProperty('background');
        cm.style.removeProperty('background-color');
        cm.style.removeProperty('backdrop-filter');
        cm.style.removeProperty('-webkit-backdrop-filter');
        cm.classList.remove('scrolled');
        clearScrolledColors(cm);
      }
      return;
    }
    var y = window.scrollY || window.pageYOffset;
    if (y > threshold) {
      nb.classList.add('scrolled');
      nb.style.setProperty('background-color', frostedBg, 'important');
      nb.style.setProperty('background-image', 'none', 'important');
      nb.style.setProperty('--frosted-text', scrolledTextColor);
      nb.style.backdropFilter = 'blur(12px)';
      nb.style.webkitBackdropFilter = 'blur(12px)';
      nb.style.boxShadow = '0 2px 16px rgba(0,0,0,0.12)';
      setScrolledColors(nb, scrolledTextColor);
      if (cm) {
        cm.classList.add('scrolled');
        cm.style.setProperty('background', frostedBg, 'important');
        cm.style.setProperty('backdrop-filter', 'blur(12px)', 'important');
        cm.style.setProperty('-webkit-backdrop-filter', 'blur(12px)', 'important');
        setScrolledColors(cm, scrolledTextColor);
      }
    } else {
      nb.classList.remove('scrolled');
      nb.style.setProperty('background-color', 'transparent', 'important');
      nb.style.removeProperty('background-image');
      nb.style.removeProperty('--frosted-text');
      nb.style.backdropFilter = 'none';
      nb.style.webkitBackdropFilter = 'none';
      nb.style.boxShadow = 'none';
      clearScrolledColors(nb);
      if (cm) {
        cm.classList.remove('scrolled');
        cm.style.setProperty('background', 'transparent', 'important');
        cm.style.setProperty('backdrop-filter', 'none', 'important');
        cm.style.setProperty('-webkit-backdrop-filter', 'none', 'important');
        clearScrolledColors(cm);
      }
    }
  }
  window.addEventListener('scroll', onScroll, { passive: true });
  window.addEventListener('resize', onScroll, { passive: true });
  window._zappyNavScrollCleanup = function() { window.removeEventListener('scroll', onScroll); window.removeEventListener('resize', onScroll); };
  onScroll();

  // On pages without a dark hero, the transparent navbar shows light text on
  // a light background — invisible. Detect this and lock the frosted state.
  function srgbLuminance(rv, gv, bv) {
    rv /= 255; gv /= 255; bv /= 255;
    rv = rv <= 0.03928 ? rv / 12.92 : Math.pow((rv + 0.055) / 1.055, 2.4);
    gv = gv <= 0.03928 ? gv / 12.92 : Math.pow((gv + 0.055) / 1.055, 2.4);
    bv = bv <= 0.03928 ? bv / 12.92 : Math.pow((bv + 0.055) / 1.055, 2.4);
    return 0.2126 * rv + 0.7152 * gv + 0.0722 * bv;
  }
  var heroEl = document.querySelector('section[class*="hero"], [data-hero-type], main > section:first-child');
  var pageHasDarkHero = false;
  if (heroEl) {
    var hCs = getComputedStyle(heroEl);
    var heroBgImg = hCs.backgroundImage;
    if (heroBgImg && heroBgImg !== 'none') {
      if (heroBgImg.indexOf('url(') !== -1) {
        // Photo background — assume dark (typically has dark overlay)
        pageHasDarkHero = true;
      } else if (heroBgImg.indexOf('gradient') !== -1) {
        // CSS gradient — parse RGB stops and calculate average luminance
        var colorMatches = heroBgImg.match(/rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/g);
        if (colorMatches && colorMatches.length > 0) {
          var totalLum = 0;
          for (var ci = 0; ci < colorMatches.length; ci++) {
            var parts = colorMatches[ci].match(/\d+/g);
            totalLum += srgbLuminance(parseInt(parts[0]), parseInt(parts[1]), parseInt(parts[2]));
          }
          pageHasDarkHero = (totalLum / colorMatches.length) < 0.4;
        } else {
          pageHasDarkHero = true;
        }
      } else {
        pageHasDarkHero = true;
      }
    } else {
      var hBgM = hCs.backgroundColor.match(/\d+/g);
      if (hBgM && hBgM.length >= 3) {
        pageHasDarkHero = srgbLuminance(parseInt(hBgM[0]), parseInt(hBgM[1]), parseInt(hBgM[2])) < 0.4;
      }
    }
  }
  if (!pageHasDarkHero) {
    window.removeEventListener('scroll', onScroll);
    window.removeEventListener('resize', onScroll);
    // Apply the locked frosted state in a WIDTH-RESPONSIVE way. The .scrolled
    // class is added on every viewport (so the CSS solid-bg + mobile link-color
    // rules apply), but the frosted glass + inline scrolled text color are only
    // applied on DESKTOP. On mobile the open menu is a solid, full-screen panel
    // whose background is independent of the navbar bar's frosted background, so
    // stamping the desktop frosted text color (computed from the page bg) as an
    // inline color:!important on every menu link renders the items invisible
    // (dark-on-dark). The mobile link colors are owned by the
    // @media(max-width:768px) CSS rules instead.
    //
    // CRITICAL: this must run on resize too, NOT just once. A preview/editor
    // iframe (Preview.js loads at desktop width, then resizes to a 375px phone
    // frame WITHOUT reloading) — and desktop devtools mobile emulation — both
    // initialize this script at a desktop width and only later become mobile.
    // If we stamped the desktop frosted color once and stopped listening, the
    // dark inline color would persist onto the mobile menu panel. So re-apply
    // the width-correct state on every resize.
    function applyLockedState() {
      var desktop = window.innerWidth > 768;
      nb.classList.add('scrolled');
      if (desktop) {
        nb.style.setProperty('--frosted-text', scrolledTextColor);
        nb.style.setProperty('background-image', 'none', 'important');
        nb.style.setProperty('background-color', frostedBg, 'important');
        nb.style.backdropFilter = 'blur(12px)';
        nb.style.webkitBackdropFilter = 'blur(12px)';
        nb.style.boxShadow = '0 2px 16px rgba(0,0,0,0.12)';
        setScrolledColors(nb, scrolledTextColor);
      } else {
        // Mobile: hand the link colors back to CSS and drop the inline frosted
        // styling (incl. backdrop-filter, which would re-establish a
        // fixed-positioning containing block and collapse the open menu).
        nb.style.removeProperty('--frosted-text');
        nb.style.removeProperty('background-image');
        nb.style.removeProperty('background-color');
        nb.style.backdropFilter = '';
        nb.style.webkitBackdropFilter = '';
        nb.style.boxShadow = '';
        clearScrolledColors(nb);
      }
      if (cm) {
        cm.classList.add('scrolled');
        if (desktop) {
          cm.style.setProperty('background', frostedBg, 'important');
          cm.style.setProperty('backdrop-filter', 'blur(12px)', 'important');
          cm.style.setProperty('-webkit-backdrop-filter', 'blur(12px)', 'important');
          setScrolledColors(cm, scrolledTextColor);
        } else {
          cm.style.removeProperty('background');
          cm.style.removeProperty('backdrop-filter');
          cm.style.removeProperty('-webkit-backdrop-filter');
          clearScrolledColors(cm);
        }
      }
    }
    applyLockedState();
    window.addEventListener('resize', applyLockedState, { passive: true });
  }
}

// Initialize featured products, categories, and product/category page details on load
document.addEventListener('DOMContentLoaded', function() {
  // Mobile menu is handled by the main navbar script - no separate e-commerce handler needed
  
  // Hide sub-navbars on product/checkout/order pages
  handleSubNavbarVisibility();

  // Activate frosted glass scroll effect for transparent navbars
  initTransparentNavbarScrollEffect();

  // Fetch store settings first (handles announcement bar, product layout, etc.)
  fetchAdditionalJsSettings();
  loadFeaturedProducts();
  loadFeaturedCategories();
  loadCatalogCategories();
  loadProductDetailPage();
  loadCategoryPage();
  repairCatalogSubmenuLabel();
  
  // Register language change callback to refresh e-commerce content
  // This ensures translated product names, categories, etc. are displayed when switching languages
  if (typeof zappyI18n !== 'undefined' && typeof zappyI18n.onLanguageChange === 'function') {
    zappyI18n.onLanguageChange(function(newLang, oldLang) {
      console.log('[E-COMMERCE] Language changed from ' + oldLang + ' to ' + newLang + ', refreshing content...');
      
      // Refresh all e-commerce content with the new language
      // Each function uses buildApiUrlWithLang which will now include the new language
      fetchAdditionalJsSettings(true);  // Force refresh announcement bar with translated messages
      loadFeaturedProducts();           // Refresh featured products section
      loadFeaturedCategories();         // Refresh featured categories section
      loadCatalogCategories();          // Refresh navigation category menu
      
      // If we're on a product detail page, refresh it
      var detailSection = document.getElementById('product-detail');
      if (detailSection) {
        loadProductDetailPage();
      }
      
      // If we're on a category page, refresh it
      var categorySection = document.getElementById('category-products');
      if (categorySection) {
        loadCategoryPage();
      }
      
      // If we're on the products listing page, refresh it
      var productsGrid = document.getElementById('zappy-product-grid');
      if (productsGrid && typeof loadProducts === 'function') {
        loadProducts();
      }
      
      // Update static e-commerce UI elements that are rendered at page generation time
      // These need to be manually updated when language changes
      updateStaticEcommerceUI();
      repairCatalogSubmenuLabel();
      scheduleProductsListingTitleRepair();
      // NOTE: cart/checkout re-pricing (renderCart, renderCartDrawer,
      // loadShippingMethods, updateOrderTotals) is handled by the MAIN script's
      // language-change handler — those functions live in that closure and are
      // not reachable from here, so calling them in this block would be a no-op.
    });
    console.log('[E-COMMERCE] Registered language change callback for content refresh');
  }
  
  // Update static e-commerce UI elements with translated text
  function updateStaticEcommerceUI() {
    // Update "Add to Cart" button on product detail page
    var addToCartBtn = document.getElementById('add-to-cart-btn');
    if (addToCartBtn) {
      addToCartBtn.textContent = getEcomText('addToCart', 'Add to Cart');
    }
    
    // Update all other "Add to Cart" buttons in product grids
    document.querySelectorAll('button.add-to-cart:not(#add-to-cart-btn)').forEach(function(btn) {
      // Only update text content, preserve onclick handler
      btn.textContent = getEcomText('addToCart', 'Add to Cart');
    });
    
    // Update filter buttons text (All, Featured, New, Sale)
    document.querySelectorAll('.filter-btn').forEach(function(btn) {
      var category = btn.getAttribute('data-category');
      if (category === 'all') {
        btn.textContent = getEcomText('all', 'All');
      } else if (category === 'featured') {
        btn.textContent = getEcomText('featured', 'Featured');
      } else if (category === 'new') {
        btn.textContent = getEcomText('new', 'New');
      } else if (category === 'sale') {
        btn.textContent = getEcomText('sale', 'Sale');
      }
    });

    repairProductsListingTitle();
    repairCatalogSubmenuLabel();
    
    // Update cart drawer empty message
    var emptyCartMsg = document.querySelector('.empty-cart p');
    if (emptyCartMsg) {
      emptyCartMsg.textContent = getEcomText('emptyCart', 'Your cart is empty');
    }
    
    // Update checkout button text
    var checkoutBtn = document.querySelector('.checkout-btn, #checkout-btn');
    if (checkoutBtn) {
      checkoutBtn.textContent = getEcomText('proceedToCheckout', 'Proceed to Checkout');
    }

    var staticTextSelectors = [
      ['.cart-section h1', 'yourCart', 'Your Cart'],
      ['.cart-total', 'total', 'Total'],
      ['.checkout-section > h1', 'checkout', 'Checkout'],
      ['.checkout-accordion-panel[data-step="contact"] .checkout-accordion-title', 'contactInformation', 'Contact Information'],
      ['.checkout-accordion-panel[data-step="shipping"] .checkout-accordion-title', 'shippingMethod', 'Shipping Method'],
      ['.checkout-accordion-panel[data-step="payment"] .checkout-accordion-title', 'payment', 'Payment'],
      ['.checkout-accordion-panel[data-step="items"] .checkout-accordion-title', 'items', 'Items'],
      ['.checkout-order-details-title', 'orderDetails', 'Order Details'],
      ['#coupon-toggle-btn', 'haveCouponCode', 'I have a coupon code'],
      ['#apply-coupon-btn', 'applyCoupon', 'Apply'],
      ['#remove-coupon-btn', 'removeCoupon', 'Remove'],
      ['#place-order-btn', 'placeOrder', 'Place Order'],
      ['#checkout-login-link', 'loginHere', 'Login here'],
      ['#checkout-logout-btn', 'logout', 'Logout']
    ];
    staticTextSelectors.forEach(function(entry) {
      var el = document.querySelector(entry[0]);
      if (el && !el.querySelector('svg')) {
        el.textContent = getEcomText(entry[1], entry[2]);
      } else if (el && entry[0] === '#coupon-toggle-btn') {
        var svg = el.querySelector('svg');
        el.textContent = '';
        if (svg) el.appendChild(svg);
        el.appendChild(document.createTextNode(' ' + getEcomText(entry[1], entry[2])));
      }
    });

    var labels = [
      ['label[for="customer-name"]', 'fullName', 'Full Name', ' *'],
      ['label[for="customer-phone"]', 'mobileNumber', 'Mobile Number', ' *'],
      ['label[for="customer-email"]', 'email', 'Email', ' *'],
      ['label[for="shipping-state"]', 'stateProvince', 'State / Province', ' *'],
      ['label[for="shipping-city"]', 'city', 'City', ' *'],
      ['label[for="shipping-street"]', 'streetAndNumber', 'Street and Number', ' *'],
      ['label[for="shipping-apartment"]', 'apartmentExt', 'Apt, Floor, Building Code, Notes, Etc.', ''],
      ['label[for="shipping-zip"]', 'zipPostal', 'Zip / Postal Code', '']
    ];
    labels.forEach(function(entry) {
      var el = document.querySelector(entry[0]);
      if (el) el.textContent = getEcomText(entry[1], entry[2]) + entry[3];
    });

    var placeholders = [
      ['#customer-name', 'fullName', 'Full Name'],
      ['#customer-phone', 'phone', 'Phone'],
      ['#customer-email', 'emailAddress', 'Email Address'],
      ['#shipping-city', 'city', 'City'],
      ['#shipping-street', 'streetAndNumber', 'Street and Number'],
      ['#shipping-apartment', 'apartmentExt', 'Apt, Floor, Building Code, Notes, Etc.'],
      ['#shipping-zip', 'zipPostal', 'Zip / Postal Code'],
      ['#coupon-code-input', 'enterCouponCode', 'Enter coupon code']
    ];
    placeholders.forEach(function(entry) {
      var el = document.querySelector(entry[0]);
      if (el) el.setAttribute('placeholder', getEcomText(entry[1], entry[2]));
    });

    document.querySelectorAll('.checkout-next-btn').forEach(function(btn) {
      btn.textContent = getEcomText('next', 'Next');
    });

    var alreadySpan = document.querySelector('#checkout-already-have-account') ||
      (document.querySelector('#checkout-login-prompt') && document.querySelector('#checkout-login-prompt').querySelector('span'));
    if (alreadySpan) alreadySpan.textContent = getEcomText('alreadyHaveAccount', 'Already have an account?');

    var loggedInLabel = document.querySelector('#checkout-logged-in-label') ||
      (document.querySelector('.checkout-logged-in-text') && document.querySelector('.checkout-logged-in-text').querySelector('span'));
    if (loggedInLabel) loggedInLabel.textContent = getEcomText('loggedInAs', 'Logged in as');

    var saveAddress = document.querySelector('[data-i18n="ecom_saveAddressForNextTime"]');
    if (saveAddress) saveAddress.textContent = getEcomText('saveAddressForNextTime', 'Save this address for next time');
    var agreeTerms = document.querySelector('[data-i18n="ecom_agreeToTerms"]');
    if (agreeTerms) agreeTerms.textContent = getEcomText('agreeToTerms', 'I agree to the');
    var termsLink = document.querySelector('[data-i18n="ecom_termsAndConditions"]');
    if (termsLink) termsLink.textContent = getEcomText('termsAndConditions', 'Terms of Use');
    var orderLabels = [
      ['subtotal', 'subtotal', 'Subtotal'],
      ['vatIncluded', 'vatIncluded', 'Including VAT'],
      ['shipping', 'shipping', 'Shipping'],
      ['discount', 'discount', 'Discount'],
      ['totalToPay', 'totalToPay', 'Total to Pay']
    ];
    orderLabels.forEach(function(entry) {
      var labelEl = document.querySelector('[data-ecom-label="' + entry[0] + '"]');
      if (labelEl) labelEl.textContent = getEcomText(entry[1], entry[2]) + ':';
    });
    
    console.log('[E-COMMERCE] Static UI elements updated for language change');
  }
  updateStaticEcommerceUI();
  scheduleProductsListingTitleRepair();
});

